/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel. In production
 * this would integrate with an SMTP service or email API (SendGrid,
 * AWS SES, etc.). Currently stubs delivery and logs the attempt.
 *
 * ## Usage
 * ```ts
 * const emailAdapter = new EmailAdapter(eventBus);
 * notificationService.registerAdapter(emailAdapter);
 * ```
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSendEvent } from '../events/event-types.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';
import type { NotificationAdapter } from './notification.adapter.js';

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');

  /** Sent payloads — exposed for testing. */
  private sent: NotificationPayload[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandler();
  }

  /**
   * Subscribe to notification:send events and handle email-channel payloads.
   */
  private registerHandler(): void {
    this.eventBus.on<NotificationSendEvent>('notification:send', async (event) => {
      if (event.payload.channel === this.channel) {
        await this.send(event.payload);
      }
    });
  }

  /**
   * Deliver an email notification.
   *
   * Currently a stub that records the payload. In production, replace
   * the body of this method with actual SMTP / email-API integration.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      this.logger.info(
        `Sending email to ${payload.recipient}: "${payload.subject}"`,
      );

      // --- Stub: record the payload instead of actually sending ---
      this.sent.push(payload);

      return { success: true };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown email delivery error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all payloads that were "sent" (useful for testing).
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sent];
  }

  /**
   * Clear the sent emails list (useful for testing).
   */
  clearSentEmails(): void {
    this.sent = [];
  }
}

/**
 * Notification service — orchestrates notification creation and delivery.
 *
 * ## Architecture
 * This service uses a **fully event-driven** pattern:
 *
 * 1. **Inbound**: Domain events (order:created, order:status-changed, etc.)
 *    arrive via EventBus. The service translates them into NotificationPayloads.
 *
 * 2. **Outbound**: The service emits `notification:send` events on the EventBus.
 *    Registered NotificationAdapters subscribe to these events and handle
 *    channel-specific delivery (email, webhook, in-app, etc.).
 *
 * ## Constraints
 * - ALL notifications flow through this service — no direct adapter calls.
 * - ALL domain-event-to-notification mapping lives here.
 * - ALL delivery is delegated to adapters via the `notification:send` event.
 * - Adapters MUST implement the NotificationAdapter interface.
 * - Adapters MUST be registered via `registerAdapter()` before notifications
 *   targeting their channel will be delivered.
 *
 * ## Adding a new notification trigger
 * 1. Subscribe to the relevant domain event in `registerEventHandlers()`.
 * 2. Create a handler that builds a NotificationPayload.
 * 3. Call `this.dispatchNotification(payload)` to emit and persist.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and dispatching to adapters
 */

import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  // ---------------------------------------------------------------------------
  // Event handlers — translate domain events into notifications
  // ---------------------------------------------------------------------------

  /**
   * Subscribe to domain events that should trigger notifications.
   * All subscriptions use EventBus — no CallbackRegistry, no direct calls.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation email to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      notificationType: 'order_confirmation',
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      notificationType: 'order_status_update',
      channel: 'email',
      priority: 'normal',
    });
  }

  // ---------------------------------------------------------------------------
  // Core dispatch — persist + emit notification:send event
  // ---------------------------------------------------------------------------

  /**
   * Dispatch a notification: persist a record and emit a notification:send event.
   *
   * This is the single exit point for all notifications. Other agents should
   * call this method (or let event handlers call it) rather than emitting
   * notification:send directly.
   */
  private dispatchNotification(payload: NotificationPayload): void {
    const priority: NotificationPriority = payload.priority ?? 'normal';

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      notificationType: payload.notificationType,
      channel: payload.channel,
      priority,
      delivered: false,
      createdAt: new Date(),
    };
    this.notifications.push(notification);

    // Emit for adapters to pick up
    this.eventBus.emit({
      type: 'notification:send',
      payload: { ...payload, priority },
      timestamp: notification.createdAt,
    });

    this.logger.info(`Notification dispatched: ${notification.id} to ${payload.recipient}`);
  }

  // ---------------------------------------------------------------------------
  // Query methods
  // ---------------------------------------------------------------------------

  /** Get all notifications. */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /** Get notifications for a specific recipient. */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /** Get the count of notifications. */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /** Clear all notifications (useful for testing). */
  clearNotifications(): void {
    this.notifications = [];
  }
}

