+/**
+ * Notification model and related types.
+ *
+ * Notifications are created by the NotificationService in response to
+ * domain events (via EventBus). Each notification targets a recipient
+ * through a specific channel and is dispatched by a NotificationAdapter.
+ */
+
+/** Supported notification delivery channels. */
+export type NotificationChannel = 'email' | 'webhook' | 'in-app';
+
+/**
+ * Priority levels for notifications.
+ * Adapters may use this to decide delivery urgency.
+ */
+export type NotificationPriority = 'low' | 'normal' | 'high';
+
+/**
+ * Categorizes the trigger that caused the notification.
+ * Add new types here as the system grows.
+ */
+export type NotificationType =
+  | 'order_confirmation'
+  | 'order_status_update'
+  | 'user_welcome'
+  | 'user_update';
+
+/**
+ * The payload passed to a NotificationAdapter for delivery.
+ * Adapters receive this and translate it to channel-specific formats.
+ */
+export interface NotificationPayload {
+  /** Target recipient identifier (email address, user ID, webhook URL, etc.). */
+  recipient: string;
+  /** Short summary — used as email subject, push title, etc. */
+  subject: string;
+  /** Full notification body. */
+  body: string;
+  /** What triggered this notification. */
+  notificationType: NotificationType;
+  /** Delivery channel. */
+  channel: NotificationChannel;
+  /** Delivery priority. Defaults to 'normal' if omitted. */
+  priority?: NotificationPriority;
+  /** Arbitrary metadata adapters can use (e.g., template IDs, deep links). */
+  metadata?: Record<string, string>;
+}
+
+/**
+ * The delivery result returned by an adapter after attempting to send.
+ */
+export interface NotificationResult {
+  /** Whether the adapter accepted the notification for delivery. */
+  success: boolean;
+  /** Adapter-specific error message on failure. */
+  error?: string;
+}
+
+/**
+ * A persisted notification record, stored by NotificationService.
+ */
+export interface Notification {
+  /** Auto-generated ID (notif-0001, notif-0002, ...). */
+  id: string;
+  /** Recipient identifier. */
+  recipient: string;
+  /** Short summary. */
+  subject: string;
+  /** Full body. */
+  body: string;
+  /** What triggered this notification. */
+  notificationType: NotificationType;
+  /** Channel used for delivery. */
+  channel: NotificationChannel;
+  /** Delivery priority. */
+  priority: NotificationPriority;
+  /** Whether the adapter reported successful delivery. */
+  delivered: boolean;
+  /** Error message if delivery failed. */
+  error?: string;
+  /** When the notification was created. */
+  createdAt: Date;
+}

